class Solution:
    def minMovesToMakePalindrome(self, s: str) -> int:
        n = len(s)
        s = list(s)
        moves = 0
        left, right = 0, n - 1
        while left < right:
            if s[left] != s[right]:
                mid = right
                while mid > left and s[left] != s[mid]:
                    mid -= 1
                if mid == left:
                    return -1  # should not happen according to problem statement
                moves += right - mid
                for i in range(mid, right):
                    s[i], s[i + 1] = s[i + 1], s[i]
            left += 1
            right -= 1
        return moves

